import { useRef } from 'react';
import { replaceEqualDeep } from '#registry/default/lib/replace-equal-deep.ts';

type FunctionType = (...args: any[]) => any;

/**
 * Memoizes a value deeply and returns a value that is as equal as possible to the input value.
 * This method is also used inside react-query to memoize query results.
 * This is an advanced version of `useMemoCompare`.
 */
export function useStructuralSharing<T, TRet = T extends FunctionType ? ReturnType<T> : T>(value: T) {
  const resolvedValue = typeof value === 'function' ? value() : value;
  const memoRef = useRef<TRet>(resolvedValue);

  if (resolvedValue !== memoRef.current) {
    memoRef.current = replaceEqualDeep(memoRef.current, resolvedValue);
  }

  return memoRef.current;
}
